const has=(a,s)=>a.some(w=>s.indexOf(w)!==-1);
// Known ATS platforms -> likely a real recruiter. Add your own.
const ALLOW=['greenhouse.io','comeet','sparkhire','lever.co','myworkday','ashbyhq','workable','careers.examplecorp'];
// LinkedIn direct messages (a human) -> keep as LOG
const LIDM=['sent you a message','sent you a new message','sent you an inmail'];
// LinkedIn automated job-alert digests -> IGNORE (sender + phrases)
const LIDIGEST=['jobalerts-noreply','jobs-noreply@linkedin','jobs-listings@linkedin'];
const LIJOB=['jobs similar to','view jobs in',' is hiring','you appeared in','competing against these','new jobs in','match your preferences','job alert for'];
// Recruiter/job keywords, English + Hebrew
const JOB=['recruit','talent acquisition','position','the role','opportunity','architect','engineer','interview','משרה','משרת','משרות','מגייס','מגייסת','גיוס','דרוש','דרושה','קורות חיים','מועמד','תפקיד','הזדמנות','השמה','ראיון','להוביל','קבוצת'];
const NOISE=['unsubscribe','newsletter','webinar','medium daily digest','invites you to a new event','dependabot','renovate','noreply@github',' sale','% off','coupon','cashback'];
const out=[];
for(const item of $input.all()){
  const j=item.json;
  const id=String(j.id||j.messageId||'');
  const from=String(j.From||j.from||'').toLowerCase();
  const subject=String(j.Subject||j.subject||'');
  const snippet=String(j.snippet||j.text||'');
  const en=(from+' '+subject+' '+snippet).toLowerCase();
  let bucket,reason,needsLLM=false;
  if(has(ALLOW,from)){bucket='ALERT';reason='ATS/recruiter sender';needsLLM=true;}
  else if(has(LIDM,en)){bucket='LOG';reason='LinkedIn DM';}
  else if(has(LIDIGEST,from)||has(LIJOB,en)){bucket='IGNORE';reason='LinkedIn job-alert digest';}
  else if(has(JOB,en)){bucket='LOG';reason='recruiter/job signal';needsLLM=true;}
  else if(has(NOISE,en)){bucket='IGNORE';reason='noise';}
  else{bucket='IGNORE';reason='no job signal';}
  const llmPrompt='Triage this inbox email into ONE word: ALERT, LOG, or IGNORE. Email may be Hebrew or English. ALERT=a human recruiter message, interview invite, or rejection from a real application. LOG=job alert, application-viewed, or unsure. IGNORE=newsletter, marketing, or digest. When unsure answer LOG. From: '+from+' Subject: '+subject+' Snippet: '+snippet.slice(0,300);
  out.push({json:{bucket,reason,needsLLM,id,from,subject,snippet:snippet.slice(0,300),llmPrompt}});
}
return out;
